const RETELL_KEY = 'REDACTED_RETELL_KEY';
const N8N_KEY = 'REDACTED_JWT';
const SB_URL = 'https://hgheyqwnrcvwtgngqdnq.supabase.co';
const SB_KEY = 'REDACTED_JWT';
const GH_TOKEN = 'REDACTED_GH_TOKEN';
const REPO = 'Syntharra/syntharra-automations';
const GH_BASE = 'https://api.github.com';
const ghH = { 'Authorization': 'token ' + GH_TOKEN, 'Accept': 'application/vnd.github.v3+json', 'Content-Type': 'application/json' };
const retellH = { 'Authorization': 'Bearer ' + RETELL_KEY };
const n8nH = { 'X-N8N-API-KEY': N8N_KEY };
const sbH = { 'apikey': SB_KEY, 'Authorization': 'Bearer ' + SB_KEY };
const date = new Date().toISOString().split('T')[0];
const results = [];

async function ghPush(path, str, msg) {
  const encoded = Buffer.from(str).toString('base64');
  const url = GH_BASE + '/repos/' + REPO + '/contents/' + path;
  let sha = null;
  try { const r = await $http.request({ method: 'GET', url, headers: ghH }); sha = r.data.sha; } catch(e) {}
  const body = { message: msg, content: encoded };
  if (sha) body.sha = sha;
  const r = await $http.request({ method: 'PUT', url, headers: ghH, body: JSON.stringify(body) });
  return r.data.commit.sha.slice(0,10);
}

function redact(s) {
  return s
    .replace(/KEY[0-9A-Fa-f_]{20,}/g,'[TELNYX_REDACTED]')
    .replace(/AIzaSy[A-Za-z0-9_-]+/g,'[GOOGLE_REDACTED]')
    .replace(/whsec_[A-Za-z0-9]+/g,'[STRIPE_REDACTED]')
    .replace(/ghp_[A-Za-z0-9]+/g,'[GH_TOKEN_REDACTED]');
}

// ── 1. Retell live 12-node flow ───────────────────────────────────────────────
try {
  const r = await $http.request({ method: 'GET', url: 'https://api.retellai.com/get-conversation-flow/conversation_flow_ed1ff4a600af', headers: retellH });
  const sha = await ghPush('hvac-standard/backups/conversation_flow_ed1ff4a600af_LIVE.json', JSON.stringify(r.data, null, 2), 'nightly: Retell flow - ' + date);
  results.push({ item: 'retell_flow', status: 'ok', sha });
} catch(e) { results.push({ item: 'retell_flow', status: 'error', error: e.message }); }

// ── 2. Retell agents ──────────────────────────────────────────────────────────
try {
  const r = await $http.request({ method: 'GET', url: 'https://api.retellai.com/list-agents', headers: retellH });
  const seen = new Set();
  const unique = r.data.filter(a => { if(seen.has(a.agent_id)) return false; seen.add(a.agent_id); return true; });
  const sha = await ghPush('hvac-standard/backups/agents_LIVE.json', JSON.stringify(unique, null, 2), 'nightly: Retell agents - ' + date);
  results.push({ item: 'retell_agents', status: 'ok', sha });
} catch(e) { results.push({ item: 'retell_agents', status: 'error', error: e.message }); }

// ── 3. Readable prompt export (Markdown) ─────────────────────────────────────
try {
  const r = await $http.request({ method: 'GET', url: 'https://api.retellai.com/get-conversation-flow/conversation_flow_ed1ff4a600af', headers: retellH });
  const flow = r.data;
  let md = '# HVAC Standard Agent — Prompt Export\n';
  md += `_Exported: ${date}_\n\n`;
  md += '---\n\n## Global Prompt\n\n```\n' + (flow.global_prompt || '') + '\n```\n\n---\n\n## Nodes\n\n';
  for (const node of (flow.nodes || [])) {
    md += `### ${node.name} (${node.type})\n\n`;
    const instr = node.instruction;
    if (instr) {
      const text = typeof instr === 'string' ? instr : (instr.text || JSON.stringify(instr));
      md += '**Instruction:**\n```\n' + text + '\n```\n\n';
    }
    const edges = node.edges || (node.edge ? [node.edge] : []);
    if (edges.length) {
      md += '**Edges:**\n';
      for (const e of edges) {
        const cond = e.transition_condition?.prompt || e.condition || 'default';
        md += `- → \`${e.destination_node_id}\` (${cond})\n`;
      }
      md += '\n';
    }
  }
  const sha = await ghPush('hvac-standard/prompts/HVAC_Standard_Prompts.md', md, 'nightly: readable prompt export - ' + date);
  results.push({ item: 'prompt_export', status: 'ok', sha });
} catch(e) { results.push({ item: 'prompt_export', status: 'error', error: e.message }); }

// ── 4. Supabase schema ────────────────────────────────────────────────────────
try {
  const tables = ['hvac_standard_agent', 'hvac_call_log', 'stripe_payment_data', 'client_subscriptions', 'billing_cycles', 'overage_charges'];
  let schema = '# Syntharra Supabase Schema\n\n_Exported: ' + date + '_\n\n';
  for (const table of tables) {
    try {
      const r = await $http.request({
        method: 'GET',
        url: SB_URL + '/rest/v1/' + table + '?limit=0',
        headers: { ...sbH, 'Accept': 'application/json', 'Prefer': 'count=exact' }
      });
      // Get columns via introspection
      const r2 = await $http.request({
        method: 'GET',
        url: SB_URL + '/rest/v1/' + table + '?limit=1',
        headers: sbH
      });
      const cols = r2.data && r2.data.length > 0 ? Object.keys(r2.data[0]) : [];
      schema += '## ' + table + '\n\nColumns: ' + (cols.length ? cols.join(', ') : 'empty table') + '\n\n';
    } catch(e) {
      schema += '## ' + table + '\n\nError fetching: ' + e.message + '\n\n';
    }
  }
  // Also get full schema via Supabase introspection endpoint
  try {
    const r3 = await $http.request({
      method: 'GET',
      url: SB_URL + '/rest/v1/?apikey=' + SB_KEY,
      headers: sbH
    });
    schema += '\n## Full OpenAPI Schema\n\n```json\n' + JSON.stringify(r3.data, null, 2).slice(0, 50000) + '\n```\n';
  } catch(e) {}

  const sha = await ghPush('supabase/schema_LIVE.md', schema, 'nightly: Supabase schema - ' + date);
  results.push({ item: 'supabase_schema', status: 'ok', sha });
} catch(e) { results.push({ item: 'supabase_schema', status: 'error', error: e.message }); }

// ── 5. n8n workflows ──────────────────────────────────────────────────────────
const wfs = {
  'call-processor': 'OyDCyiOjG0twguXq',
  'onboarding': 'k0KeQxWb3j3BbQEk',
  'stripe': 'ydzfhitWiF5wNzEy',
  'weekly-lead-report': 'mFuiB4pyXyWSIM5P',
  'minutes-calculator': '9SuchBjqhFmLbH8o',
  'usage-alert': 'lQsYJWQeP5YPikam',
  'publish-retell': 'sBFhshlsz31L6FV8',
  'welcome-email-manual': 'Rd5HiN7v2SRwNmiY',
};
for (const [name, wfId] of Object.entries(wfs)) {
  try {
    const r = await $http.request({ method: 'GET', url: 'https://syntharra.app.n8n.cloud/api/v1/workflows/' + wfId, headers: n8nH });
    const sha = await ghPush('hvac-standard/n8n-workflows/' + name + '_' + wfId + '.json', redact(JSON.stringify(r.data, null, 2)), 'nightly: n8n ' + name + ' - ' + date);
    results.push({ item: 'n8n_' + name, status: 'ok', sha });
  } catch(e) { results.push({ item: 'n8n_' + name, status: 'error', error: e.message }); }
}

return results.map(r => ({ json: r }));

